# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.
# Category: path_traversal

package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.io.File
import java.nio.file.{Paths, Files}

@Singleton
class FileController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {

  def serveFile(filename: String) = Action { implicit request =>
    try {
      val normalizedPath = Paths.get(s"uploads/$filename").normalize().toAbsolutePath()
      val uploadsPath = Paths.get("uploads").normalize().toAbsolutePath()
      
      if (!normalizedPath.startsWith(uploadsPath)) {
        BadRequest("Invalid file path")
      } else {
        val file = normalizedPath.toFile
        
        if (!file.exists() || !file.isFile) {
          NotFound("File not found")
        } else {
          val source = Source.fromFile(file)
          try {
            val content = source.mkString
            val contentType = Files.probeContentType(normalizedPath) match {
              case null => "application/octet-stream"
              case mime => mime
            }
            Ok(content).as(contentType)
          } finally {
            source.close()
          }
        }
      }
    } catch {
      case _: Exception => InternalServerError("Error reading file")
    }
  }

  def serveFileFromSubdir(subdir: String, filename: String) = Action { implicit request =>
    try {
      val normalizedPath = Paths.get(s"uploads/$subdir/$filename").normalize().toAbsolutePath()
      val uploadsPath = Paths.get("uploads").normalize().toAbsolutePath()
      
      if (!normalizedPath.startsWith(uploadsPath)) {
        BadRequest("Invalid file path")
      } else {
        val file = normalizedPath.toFile
        
        if (!file.exists() || !file.isFile) {
          NotFound("File not found")
        } else {
          val source = Source.fromFile(file)
          try {
            val content = source.mkString
            val contentType = Files.probeContentType(normalizedPath) match {
              case null => "application/octet-stream"
              case mime => mime
            }
            Ok(content).as(contentType)
          } finally {
            source.close()
          }
        }
      }
    } catch {
      case _: Exception => InternalServerError("Error reading file")
    }
  }

  def listFiles(subdir: Option[String] = None) = Action { implicit request =>
    try {
      val directory = subdir match {
        case Some(dir) => 
          val normalizedPath = Paths.get(s"uploads/$dir").normalize().toAbsolutePath()
          val uploadsPath = Paths.get("uploads").normalize().toAbsolutePath()
          if (!normalizedPath.startsWith(uploadsPath)) {
            return BadRequest("Invalid directory path")
          }
          normalizedPath.toFile
        case None => new File("uploads")
      }
      
      if (!directory.exists() || !directory.isDirectory) {
        NotFound("Directory not found")
      } else {
        val files = directory.listFiles().toList.map { file =>
          Map(
            "name" -> file.getName,
            "type" -> (if (file.isDirectory) "directory" else "file"),
            "size" -> file.length().toString
          )
        }
        Ok(play.api.libs.json.Json.toJson(files))
      }
    } catch {
      case _: Exception => InternalServerError("Error listing files")
    }
  }

  def downloadFile(filename: String) = Action { implicit request =>
    try {
      val normalizedPath = Paths.get(s"uploads/$filename").normalize().toAbsolutePath()
      val uploadsPath = Paths.get("uploads").normalize().toAbsolutePath()
      
      if (!normalizedPath.startsWith(uploadsPath)) {
        BadRequest("Invalid file path")
      } else {
        val file = normalizedPath.toFile
        
        if (!file.exists() || !file.isFile) {
          NotFound("File not found")
        } else {
          val source = Source.fromFile(file)
          try {
            val content = source.mkString
            Ok(content)
              .withHeaders(CONTENT_DISPOSITION -> s"attachment; filename=${file.getName}")
          } finally {
            source.close()
          }
        }
      }
    } catch {
      case _: Exception => InternalServerError("Error downloading file")
    }
  }
}